class efuAI {
    constructor() {
      this.aiTalkMode = false;
      this.aiPostExplanation = '';
      this.config = GLOBAL_CONFIG.post_ai; // 获取全局配置
      this.scoGPTIsRunning = false;
    }
  
    init() {
      if (!document.querySelector(".ai-explanation")) return;
      this.scoGPTIsRunning = false;
      this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;
      if (!this.aiPostExplanation) {
        this.generate();
      } else {
        this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
      }
      this.AIEngine();
    }
  
    getTitleAndContent() {
      const e = document.getElementById("article-container");
      const t = document.title;
      const n = e.getElementsByTagName("p");
      const i = e.querySelectorAll("h1, h2, h3, h4, h5");
      return (t + " " + Array.from(i).concat(Array.from(n)).map(e => e.innerText.replace(/https?:\/\/[^\s]+/g, "")).join(" ")).slice(0, 1000);
    }
  
    async generate() {
      this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent()));
    }
  
    async fetch(e, t) {
      const prompt = `${e}\n${t}`;
      const response = await fetch(this.config.apiUrl, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.config.apiKey}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: this.config.model,
          prompt: prompt,
          max_tokens: this.config.maxToken
        })
      });
      const data = await response.json();
      if (response.ok) {
        this.aiPostExplanation = data.choices[0].text;
        return data.choices[0].text;
      } else {
        console.error("Request failed:", data.error);
        return data.error;
      }
    }
  
    aiShowAnimation(promise, t = false) {
      const n = document.querySelector(".ai-explanation");
      const i = document.querySelector(".ai-tag");
      if (!n || this.scoGPTIsRunning) return;
      this.scoGPTIsRunning = true;
      this.cleanSuggestions();
      i.classList.add("loadingAI");
      n.style.display = "block";
      n.innerHTML = '生成中...<span class="blinking-cursor"></span>';
      let s, o, a = true, c = 0, r = true;
      const l = new IntersectionObserver((entries) => {
        a = entries[0].isIntersecting;
        if (a) requestAnimationFrame(o);
      }, { threshold: 0 });
      promise.then((text) => {
        s = performance.now();
        o = () => {
          if (c < text.length && a) {
            const current = performance.now();
            const elapsed = current - s;
            const nextChar = text.slice(c, c + 1);
            const isPunctuation = /[，。！、？,.!?]/.test(nextChar);
            const isAlphaNumeric = /[a-zA-Z0-9]/.test(nextChar);
            const delay = isPunctuation ? 100 * Math.random() + 100 : isAlphaNumeric ? 10 : 25;
            if (elapsed >= delay) {
              n.innerText = text.slice(0, c + 1);
              s = current;
              c++;
              if (c < text.length) {
                n.innerHTML = text.slice(0, c) + '<span class="blinking-cursor"></span>';
              } else {
                n.innerHTML = text;
                n.style.display = "block";
                this.scoGPTIsRunning = false;
                i.classList.remove("loadingAI");
                l.disconnect();
                if (t) this.createSuggestions();
              }
            }
            a && requestAnimationFrame(o);
          }
        };
        if (a && r) {
          requestAnimationFrame(o);
          r = false;
        }
        l.observe(n);
      }).catch((error) => {
        console.error("检索信息失败：", error);
        n.innerHTML = "检索信息失败";
        n.style.display = "block";
        this.scoGPTIsRunning = false;
        i.classList.remove("loadingAI");
        l.disconnect();
      });
    }
  
    AIEngine() {
      const e = document.querySelector(".ai-tag");
      e && e.addEventListener("click", () => {
        if (!this.scoGPTIsRunning) {
          this.aiTalkMode = true;
          this.aiShowAnimation(Promise.resolve(this.config.talk), true);
        }
      });
    }
  
    cleanSuggestions() {
      const e = document.querySelector(".ai-suggestions");
      if (e) e.innerHTML = "";
      else console.error("没有这个元素：'ai-suggestions'");
    }
  
    createSuggestions() {
      if (this.aiTalkMode) {
        this.cleanSuggestions();
        this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
          this.aiPostExplanation || this.generate();
          this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
        });
        if (this.config.randomPost) {
          this.createSuggestionItemWithAction("带我去看看其他文章", () => toRandomPost());
        }
        this.aiTalkMode = true;
      }
    }
  
    createSuggestionItemWithAction(text, action) {
      const suggestions = document.querySelector(".ai-suggestions");
      if (!suggestions) {
        console.error("无法找到具有class为ai-suggestions的元素");
        return;
      }
      const item = document.createElement("div");
      item.classList.add("ai-suggestions-item");
      item.textContent = text;
      item.addEventListener("click", action);
      suggestions.appendChild(item);
    }
  }
  
  const efu_ai = new efuAI;